//! World-precog sense — Thoth's "eyes" on the world.
//!
//! The afferent twin of `social_presence` (Thoth's ears): the precog
//! WHERE×WHEN×WHO geo-temporal world-model arrives as a `thoth.world-precog.v1`
//! Semantic grounding frame over the Pneuma INTERNAL stream (0x07d2 = 2002),
//! built upstream on-device (packages/precog `buildWorldPrecogFrame`). Here we
//! reconstruct it into a `PleromaticFrame` and admit it as non-authoritative
//! perception (it observes; it never commands).

use crate::pleromatic_frame::{
    PleromaticFrame, PleromaticMediaType, THOTH_WORLD_PRECOG_FRAME_KIND, THOTH_WORLD_PRECOG_THEOREM,
};

/// Pneuma INTERNAL stream id (mirror of AEON_STREAM_PNEUMA_INTERNAL).
pub const WORLD_PRECOG_PNEUMA_STREAM: u16 = 0x07d2; // 2002

/// Build a world-precog grounding frame from the on-device world summary JSON.
pub fn perceive_json(source_id: impl Into<String>, world_json: &str) -> PleromaticFrame {
    let mut frame = PleromaticFrame::grounding(
        source_id.into(),
        PleromaticMediaType::Semantic,
        world_json.as_bytes().to_vec(),
    );
    frame
        .attributes
        .insert("frame_kind".to_string(), THOTH_WORLD_PRECOG_FRAME_KIND.to_string());
    frame
        .attributes
        .insert("theorem_ref".to_string(), THOTH_WORLD_PRECOG_THEOREM.to_string());
    frame
        .attributes
        .insert("pneuma_stream".to_string(), WORLD_PRECOG_PNEUMA_STREAM.to_string());
    frame
}

/// Admit iff the frame is Semantic perception carrying the world-precog kind +
/// theorem lineage — afferent only, never an authority claim.
pub fn admit_world_precog_frame(frame: &PleromaticFrame) -> bool {
    frame.media_type == PleromaticMediaType::Semantic
        && frame
            .attributes
            .get("frame_kind")
            .map(|k| k == THOTH_WORLD_PRECOG_FRAME_KIND)
            .unwrap_or(false)
        && frame.attributes.contains_key("theorem_ref")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn world_precog_frame_admits_with_lineage() {
        let f = perceive_json(
            "monster-studio:precog",
            "{\"where\":{\"lat\":37.81213,\"lon\":-122.17943},\"whenUtcHour\":2.28}",
        );
        assert!(admit_world_precog_frame(&f));
        assert_eq!(f.media_type, PleromaticMediaType::Semantic);
        assert_eq!(
            f.attributes.get("pneuma_stream").map(String::as_str),
            Some("2002")
        );
        // the world summary survives as the frame payload
        let payload = String::from_utf8(f.data.clone()).unwrap();
        assert!(payload.contains("37.81213"));
    }

    #[test]
    fn non_world_frame_is_not_admitted() {
        let f = PleromaticFrame::grounding("x".to_string(), PleromaticMediaType::Image, vec![]);
        assert!(!admit_world_precog_frame(&f));
    }
}
